//gh-pages
// React imports
import React from 'react'
import './App.css';

// react-router-dom
import {BrowserRouter as Router, HashRouter, Route} from 'react-router-dom'
import { Link } from 'react-router-dom';

// semantic-UI imports
import {Label, Grid, Advertisement, Container, Segment, Icon, Modal } from 'semantic-ui-react';

// components imports here
import Header from "./components/Header"
import Auth from "./components/Auth/Auth"
import ModalView from "./components/ModalView"
import List from './components/List'

//screens imports here
import HomePage from './screens/HomePage'

// Images imports
import logo from './assets/logo.png'

const App = () => {


    const [activeItem, setActiveItem ] = React.useState("")
    const [open, setOpen ] = React.useState(false)

    return (
            <Router>
              <Container fluid>
                {/* computer ko navbar */}
                  <Grid>
                      <Grid.Column only="computer" fluid>
                      <Header style={{marginTop:0}} activeItem={activeItem} setActiveItem={setActiveItem}   /> 
                      </Grid.Column>
                  </Grid>

                {/* mobile ko navbar */}
                  <Grid>
                    <Grid.Row only="mobile" style={{marginTop:10}}>
                      <Grid.Column>
                        <Segment inverted >
                          <Link to=''>
                            <Label size="large" as='a' color='red' circular image>
                              <img src={logo} />
                              chotomedia 
                              <Label.Detail>.com</Label.Detail>
                            </Label>    
                          </Link>
                          <ModalView open={open} setOpen={setOpen} />
                        </Segment>
                      </Grid.Column>
                    </Grid.Row>
                  </Grid>

                {/* Nav bar ko muni ko part */}

                  <Route exact path="/">
                    <HomePage />
                    </Route>

                    <Route path="/register">
                      <Auth />
                    </Route>
                  
                  <Route path="/:name" render={
                      (props) => <List activeItem={props.match.params.name} setActiveItem={setActiveItem}/> 
                    } >
                    </Route>
              </Container>
            </Router>
              

      
        
    );
   }

export default App;
